class BankAccount:
    def __init__(self, owner, initial_balance=0):
        if initial_balance < 0:
            raise ValueError("Initial balance cannot be negative")
        self.owner = owner
        self._balance = initial_balance
        self._transactions = []

    @property
    def balance(self):
        return self._balance

    def deposit(self, amount):
        if amount <= 0:
            raise ValueError(f"Deposit amount must be positive, got {amount}")
        self._balance += amount
        self._transactions.append({'type': 'deposit', 'amount': amount})
        return self._balance

    def withdraw(self, amount):
        if amount <= 0:
            raise ValueError(f"Withdrawal amount must be positive, got {amount}")
        if amount > self._balance:
            raise ValueError(f"Insufficient funds: balance={self._balance}, requested={amount}")
        self._balance -= amount
        self._transactions.append({'type': 'withdrawal', 'amount': amount})
        return self._balance

    def transaction_count(self):
        return len(self._transactions)

# Test framework
def run_test(func):
    try:
        func()
        print(f"PASS: {func.__name__}")
        return True
    except AssertionError as e:
        print(f"FAIL: {func.__name__}: {e}")
        return False
    except Exception as e:
        print(f"ERROR: {func.__name__}: {type(e).__name__}: {e}")
        return False

# TODO: Write all these test functions:

def test_initial_balance():
    acc = BankAccount("Alice", 1000)
    assert acc.balance == 1000
    assert acc.owner == "Alice"

def test_initial_balance_defaults_zero():
    acc = BankAccount("Bob")
    assert acc.balance == 0

def test_deposit_increases_balance():
    acc = BankAccount("Alice", 100)
    new_balance = acc.deposit(50)
    assert new_balance == 150
    assert acc.balance == 150

def test_deposit_records_transaction():
    acc = BankAccount("Alice")
    acc.deposit(100)
    assert acc.transaction_count() == 1

def test_withdraw_decreases_balance():
    acc = BankAccount("Alice", 200)
    new_balance = acc.withdraw(75)
    assert new_balance == 125

def test_withdraw_exact_balance():
    acc = BankAccount("Alice", 100)
    acc.withdraw(100)
    assert acc.balance == 0

def test_withdraw_overdraft_raises():
    acc = BankAccount("Alice", 50)
    try:
        acc.withdraw(100)
        assert False, "Should have raised ValueError"
    except ValueError as e:
        assert "Insufficient funds" in str(e)

def test_deposit_zero_raises():
    acc = BankAccount("Alice", 100)
    try:
        acc.deposit(0)
        assert False, "Should have raised ValueError"
    except ValueError:
        pass  # Expected

def test_negative_initial_balance_raises():
    try:
        BankAccount("Alice", -100)
        assert False, "Should have raised ValueError"
    except ValueError:
        pass

def test_multiple_transactions():
    acc = BankAccount("Alice", 1000)
    acc.deposit(500)
    acc.withdraw(200)
    acc.deposit(100)
    assert acc.balance == 1400
    assert acc.transaction_count() == 3

tests = [
    test_initial_balance, test_initial_balance_defaults_zero,
    test_deposit_increases_balance, test_deposit_records_transaction,
    test_withdraw_decreases_balance, test_withdraw_exact_balance,
    test_withdraw_overdraft_raises, test_deposit_zero_raises,
    test_negative_initial_balance_raises, test_multiple_transactions
]

passed = sum(run_test(t) for t in tests)
print(f"\nResult: {passed}/{len(tests)} tests passed")

