def divide(a, b):
    if b == 0:
        raise ZeroDivisionError("Cannot divide by zero")
    return a / b

def test_divide_by_zero():
    try:
        divide(10, 0)
        return "FAIL: No exception raised"
    except ZeroDivisionError as e:
        return f"PASS: Caught {type(e).__name__}"

print(test_divide_by_zero())
print(f"Normal: {divide(10, 2)}")
